import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';

export default defineConfig({
  plugins: [react()],
  test: {
    environment: 'jsdom',
  },
});

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';
import './index.css';

ReactDOM.createRoot(document.getElementById('root') as HTMLElement).render(
  <React.StrictMode>
    <App />
  </React.StrictMode>,
);

import './App.css';

function App() {
  return (
    <main className="app-shell">
      <section className="app-card" aria-label="Shipyard shell">
        <p className="app-eyebrow">Shipyard</p>
        <h1>Welcome aboard</h1>
        <p className="app-copy">The app shell is ready.</p>
      </section>
    </main>
  );
}

export default App;

:root {
  font-family: Inter, system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  line-height: 1.5;
  font-weight: 400;
  color: rgba(255, 255, 255, 0.92);
  background: #0f172a;
  font-synthesis: none;
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

* {
  box-sizing: border-box;
}

html,
body,
#root {
  min-height: 100%;
  margin: 0;
}

body {
  min-height: 100vh;
}

button,
input,
textarea,
select {
  font: inherit;
}

.app-shell {
  min-height: 100vh;
  display: grid;
  place-items: center;
  padding: 24px;
  background:
    radial-gradient(circle at top, rgba(56, 189, 248, 0.18), transparent 45%),
    linear-gradient(180deg, #0f172a 0%, #111827 100%);
}

.app-card {
  width: min(100%, 520px);
  padding: 32px;
  border: 1px solid rgba(148, 163, 184, 0.2);
  border-radius: 24px;
  background: rgba(15, 23, 42, 0.72);
  box-shadow: 0 24px 80px rgba(15, 23, 42, 0.4);
  text-align: center;
}

.app-eyebrow {
  margin: 0 0 12px;
  color: #38bdf8;
  text-transform: uppercase;
  letter-spacing: 0.2em;
  font-size: 0.75rem;
  font-weight: 700;
}

.app-card h1 {
  margin: 0;
  font-size: clamp(2rem, 5vw, 3.25rem);
  line-height: 1.1;
}

.app-copy {
  margin: 16px 0 0;
  color: rgba(226, 232, 240, 0.8);
  font-size: 1.05rem;
}

import { render, screen } from '@testing-library/react';
import App from './App.js';

describe('App shell', () => {
  it('renders the Shipyard shell content', () => {
    render(<App />);

    expect(screen.getByRole('heading', { name: /welcome aboard/i })).toBeInTheDocument();
    expect(screen.getByText(/the app shell is ready\./i)).toBeInTheDocument();
    expect(screen.getByLabelText(/shipyard shell/i)).toBeInTheDocument();
  });
});

